import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import {
  LayoutDashboard,
  Users,
  DollarSign,
  CreditCard,
  TrendingUp,
  FileText,
  AlertTriangle,
  Calendar,
  BarChart3,
  PieChart,
  Activity,
  Settings,
  LogOut,
  Menu,
  X,
  Bell,
  Search
} from 'lucide-react';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';

const AdminDashboard = () => {
  const { user, logout } = useAuth();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  // Mock data - replace with actual API calls
  const mockStats = {
    totalBorrowers: 1247,
    activeLoans: 892,
    totalLoanReleased: 45678000,
    totalCollections: 52340000,
    overdueLoans: 23,
    pendingApplications: 156
  };

  useEffect(() => {
    // Simulate API call
    setTimeout(() => {
      setStats(mockStats);
      setLoading(false);
    }, 1000);
  }, []);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'borrowers', label: 'Borrowers', icon: Users },
    { id: 'applications', label: 'Loan Applications', icon: FileText },
    { id: 'loans', label: 'Active Loans', icon: CreditCard },
    { id: 'payments', label: 'Payments', icon: DollarSign },
    { id: 'products', label: 'Loan Products', icon: TrendingUp },
    { id: 'reports', label: 'Reports', icon: BarChart3 },
    { id: 'users', label: 'User Management', icon: Users },
    { id: 'settings', label: 'System Settings', icon: Settings },
  ];

  const Sidebar = ({ isOpen, onClose }) => (
    <div className={`fixed inset-y-0 left-0 z-50 w-80 bg-white/90 backdrop-blur-sm border-r border-white/20 transform ${isOpen ? 'translate-x-0' : '-translate-x-full'} transition-transform duration-300 ease-in-out lg:translate-x-0 lg:static lg:inset-0 shadow-xl`}>
      {/* Background decoration for sidebar */}
      <div className="absolute inset-0 bg-gradient-to-br from-blue-50/50 via-indigo-50/50 to-cyan-50/50"></div>

      <div className="relative z-10">
        <div className="flex items-center justify-between h-16 px-6 border-b border-white/20">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center">
              <LayoutDashboard className="w-4 h-4 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900">Loan Admin</h1>
          </div>
          <button onClick={onClose} className="lg:hidden text-gray-400 hover:text-gray-600">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="mt-8 px-4">
          <div className="space-y-2">
            {menuItems.map((item) => {
              const Icon = item.icon;
              return (
                <button
                  key={item.id}
                  onClick={() => {
                    setActiveTab(item.id);
                    setSidebarOpen(false);
                  }}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-left transition-all duration-200 ${
                    activeTab === item.id
                      ? 'bg-gradient-to-r from-blue-500 to-indigo-600 text-white shadow-lg transform scale-105'
                      : 'text-gray-600 hover:bg-white/50 hover:text-gray-900 hover:shadow-md'
                  }`}
                >
                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${
                    activeTab === item.id
                      ? 'bg-white/20'
                      : 'bg-gradient-to-br from-blue-100 to-indigo-100'
                  }`}>
                    <Icon className={`w-4 h-4 ${
                      activeTab === item.id ? 'text-white' : 'text-blue-600'
                    }`} />
                  </div>
                  <span className={`font-medium ${
                    activeTab === item.id ? 'text-white' : 'text-gray-700'
                  }`}>{item.label}</span>
                </button>
              );
            })}
          </div>

          <div className="mt-8 pt-8 border-t border-white/20">
            <button
              onClick={logout}
              className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-left text-gray-600 hover:bg-red-50 hover:text-red-600 transition-all duration-200 group"
            >
              <div className="w-8 h-8 rounded-lg flex items-center justify-center bg-gradient-to-br from-red-100 to-rose-100 group-hover:from-red-200 group-hover:to-rose-200">
                <LogOut className="w-4 h-4 text-red-600" />
              </div>
              <span className="font-medium text-gray-700 group-hover:text-red-600">Logout</span>
            </button>
          </div>
        </nav>
      </div>
    </div>
  );

  const DashboardContent = () => (
    <div className="space-y-6">
      {/* Enhanced Page Header */}
      <div className="bg-gradient-to-r from-blue-600 via-indigo-600 to-cyan-600 rounded-2xl p-6 text-white relative overflow-hidden shadow-xl">
        {/* Background Pattern */}
        <div className="absolute inset-0 opacity-20">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white rounded-full -translate-y-1/2 translate-x-1/2"></div>
          <div className="absolute bottom-0 left-0 w-24 h-24 bg-white rounded-full translate-y-1/2 -translate-x-1/2"></div>
          <div className="absolute top-1/2 left-1/4 w-20 h-20 bg-white rounded-full -translate-y-1/2"></div>
        </div>

        <div className="relative z-10 flex items-center justify-between">
          <div>
            <div className="flex items-center gap-2 text-white/90 mb-2">
              <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse shadow-md"></div>
              <span className="text-xs font-semibold uppercase tracking-wide">System Overview</span>
            </div>
            <h1 className="text-3xl font-black text-white drop-shadow-lg mb-2">Admin Dashboard</h1>
            <p className="text-white/90 text-base font-medium drop-shadow">Complete loan system overview and financial summary</p>
          </div>
          <div className="hidden lg:block">
            <button className="px-4 py-2 bg-white/25 backdrop-blur-sm hover:bg-white/35 text-white rounded-xl transition-all flex items-center gap-2 border border-white/30 shadow-lg font-medium text-sm">
              <TrendingUp className="w-4 h-4" />
              Generate Report
            </button>
          </div>
        </div>
      </div>

      {/* Enhanced Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <StatCard
          title="Total Borrowers"
          value={stats?.totalBorrowers?.toLocaleString() || '0'}
          icon={Users}
          color="blue"
          subtitle="Active customers"
        />
        <StatCard
          title="Active Loans"
          value={stats?.activeLoans?.toLocaleString() || '0'}
          icon={CreditCard}
          color="emerald"
          subtitle="Currently disbursed"
        />
        <StatCard
          title="Total Loan Released"
          value={`₱${stats?.totalLoanReleased?.toLocaleString() || '0'}`}
          icon={TrendingUp}
          color="purple"
          subtitle="This month"
        />
        <StatCard
          title="Total Collections"
          value={`₱${stats?.totalCollections?.toLocaleString() || '0'}`}
          icon={DollarSign}
          color="green"
          subtitle="Monthly revenue"
        />
        <StatCard
          title="Overdue Loans"
          value={stats?.overdueLoans?.toString() || '0'}
          icon={AlertTriangle}
          color="red"
          subtitle="Require attention"
        />
        <StatCard
          title="Pending Applications"
          value={stats?.pendingApplications?.toString() || '0'}
          icon={FileText}
          color="amber"
          subtitle="Awaiting approval"
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card title="Monthly Loan Releases" icon={BarChart3}>
          <div className="h-80 flex items-center justify-center bg-gray-50 rounded-lg">
            <div className="text-center">
              <BarChart3 className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-600">Chart visualization would be implemented here</p>
              <p className="text-sm text-gray-500 mt-2">Monthly loan disbursement trends</p>
            </div>
          </div>
        </Card>

        <Card title="Monthly Collections" icon={Activity}>
          <div className="h-80 flex items-center justify-center bg-gray-50 rounded-lg">
            <div className="text-center">
              <Activity className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-600">Chart visualization would be implemented here</p>
              <p className="text-sm text-gray-500 mt-2">Monthly payment collection trends</p>
            </div>
          </div>
        </Card>

        <Card title="Loan Status Distribution" icon={PieChart} className="lg:col-span-2">
          <div className="h-80 flex items-center justify-center bg-gray-50 rounded-lg">
            <div className="text-center">
              <PieChart className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-600">Chart visualization would be implemented here</p>
              <p className="text-sm text-gray-500 mt-2">Breakdown of loan statuses</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Recent Activity */}
      <Card title="Recent Activity" icon={Activity}>
        <div className="space-y-4">
          {[
            { type: 'loan_approved', borrower: 'John Doe', amount: '₱50,000', time: '2 hours ago' },
            { type: 'payment_received', borrower: 'Jane Smith', amount: '₱5,000', time: '4 hours ago' },
            { type: 'loan_application', borrower: 'Bob Johnson', amount: '₱25,000', time: '6 hours ago' },
            { type: 'overdue_notice', borrower: 'Alice Brown', amount: '₱3,000', time: '1 day ago' },
          ].map((activity, index) => (
            <div key={index} className="flex items-center gap-4 p-4 bg-gray-50 rounded-lg">
              <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                activity.type === 'loan_approved' ? 'bg-green-100 text-green-600' :
                activity.type === 'payment_received' ? 'bg-blue-100 text-blue-600' :
                activity.type === 'loan_application' ? 'bg-yellow-100 text-yellow-600' :
                'bg-red-100 text-red-600'
              }`}>
                {activity.type === 'loan_approved' ? <CreditCard className="w-5 h-5" /> :
                 activity.type === 'payment_received' ? <DollarSign className="w-5 h-5" /> :
                 activity.type === 'loan_application' ? <FileText className="w-5 h-5" /> :
                 <AlertTriangle className="w-5 h-5" />}
              </div>
              <div className="flex-1">
                <p className="font-medium text-gray-900">
                  {activity.type === 'loan_approved' ? 'Loan Approved' :
                   activity.type === 'payment_received' ? 'Payment Received' :
                   activity.type === 'loan_application' ? 'New Application' :
                   'Overdue Notice'}
                </p>
                <p className="text-sm text-gray-600">
                  {activity.borrower} • {activity.amount}
                </p>
              </div>
              <span className="text-sm text-gray-500">{activity.time}</span>
            </div>
          ))}
        </div>
      </Card>
    </div>
  );

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 via-blue-50 to-indigo-100 relative portal-admin">
      {/* Enhanced Background Pattern */}
      <div className="absolute inset-0 opacity-40">
        <div className="h-full w-full" style={{
          backgroundImage: `radial-gradient(circle at 20% 50%, rgba(99, 102, 241, 0.15) 0%, transparent 50%), radial-gradient(circle at 80% 80%, rgba(59, 130, 246, 0.15) 0%, transparent 50%), radial-gradient(circle at 40% 20%, rgba(6, 182, 212, 0.15) 0%, transparent 50%)`
        }}></div>
      </div>

      {/* Grid Pattern */}
      <div className="absolute inset-0 opacity-10">
        <div className="h-full w-full" style={{
          backgroundImage: `linear-gradient(rgba(99, 102, 241, 0.3) 1px, transparent 1px), linear-gradient(90deg, rgba(99, 102, 241, 0.3) 1px, transparent 1px)`,
          backgroundSize: '50px 50px'
        }}></div>
      </div>

      {/* Main Content - Full Width */}
      <div className="relative z-10">
        {/* Top Navigation Bar */}
        <header className="bg-white/95 backdrop-blur-md border-b border-gray-200/50 px-4 py-3 shadow-lg sticky top-0 z-50">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center shadow-md">
                  <LayoutDashboard className="w-4 h-4 text-white" />
                </div>
                <div className="hidden md:block">
                  <h2 className="text-lg font-semibold text-blue-600">
                    {menuItems.find(item => item.id === activeTab)?.label}
                  </h2>
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <button className="text-gray-600 hover:text-gray-900 transition-colors p-1">
                <Search className="w-4 h-4" />
              </button>
              <button className="text-gray-600 hover:text-gray-900 relative transition-colors p-1">
                <Bell className="w-4 h-4" />
                <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full"></span>
              </button>
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full flex items-center justify-center text-white text-xs font-bold shadow-md">
                  {user?.firstName?.[0] || 'A'}
                </div>
                <div className="hidden sm:block">
                  <p className="text-sm font-semibold text-gray-900">{user?.firstName || 'Admin'}</p>
                  <p className="text-xs text-gray-600">Admin</p>
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="p-6">
          {activeTab === 'dashboard' && <DashboardContent />}
          {activeTab !== 'dashboard' && (
            <div className="flex items-center justify-center h-96">
              <div className="text-center">
                <Settings className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-2">
                  {menuItems.find(item => item.id === activeTab)?.label}
                </h3>
                <p className="text-gray-600">
                  This section is under development. Dashboard content is displayed above.
                </p>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default AdminDashboard;
